func typeAbbrev(name string) string {
	if len(name) <= 3 {
		return name
	}
	return name[:3]
}

func efficacyClass(factor int64) string {
	switch factor {
	case 200:
		return "eff-super"
	case 50:
		return "eff-not"
	case 0:
		return "eff-immune"
	default:
		return "eff-normal"
	}
}

func efficacySymbol(factor int64) string {
	switch factor {
	case 200:
		return "2×"
	case 50:
		return "½"
	case 0:
		return "0"
	default:
		return ""
	}
}

func formatStatName(stat string) string {
	switch stat {
	case "attack":
		return "Attack"
	case "defense":
		return "Defense"
	case "special-attack":
		return "Sp. Atk"
	case "special-defense":
		return "Sp. Def"
	case "speed":
		return "Speed"
	default:
		return stat
	}
}

